import { test, expect } from '@playwright/test';

test('Amazon SG - Search for gibberish returns no results or limited results message', async ({ page }) => {
  // 1. Launch browser → Amazon SG.
  await page.goto('https://www.amazon.sg/');

  // 2. Search for "asdasd123!@#".
  const searchBox = page.getByRole('searchbox', { name: /search/i });
  await expect(searchBox).toBeVisible({ timeout: 10000 });
  await searchBox.fill('asdasd123!@#');
  await page.getByRole('button', { name: /search/i }).click();

  // 3. Wait for results page.
  await expect(page).toHaveURL(/k=asdasd123!@#/i, { timeout: 15000 });

  // 4. Validate "no results" or limited results message appears.
  // Amazon SG may show either a "No results for" message or "did not match any products" or similar.
  // We'll check for common no-results selectors/texts.
  const noResultsLocators = [
    page.getByText('No results for', { exact: false }),
    page.getByText('did not match any products', { exact: false }),
    page.getByText('No results found.', { exact: false }),
    page.getByText('Your search', { exact: false }).and(page.getByText('did not match any products', { exact: false })),
    page.getByText('We could not find any results for', { exact: false }),
    page.getByText('Try checking your spelling or use more general terms', { exact: false }),
  ];

  let found = false;
  for (const locator of noResultsLocators) {
    try {
      if (await locator.first().isVisible({ timeout: 5000 })) {
        found = true;
        break;
      }
    } catch (e) {
      // Continue to next locator
    }
  }

  expect(found).toBeTruthy();

  // 5. Close browser.
  // (Playwright test runner handles browser closure automatically)
});
